package com.flowmind.school;import com.flowmind.common.core.*;import org.springframework.web.bind.annotation.*;import java.time.LocalDate;import java.util.*;import java.util.concurrent.CopyOnWriteArrayList;@RestController public class SchoolController{private final List<Map<String,Object>> schools=new CopyOnWriteArrayList<>(List.of(Map.of("id",1,"name","????","region","??","level","985"),Map.of("id",2,"name","??????","region","??","level","985"),Map.of("id",3,"name","????????","region","??","level","211")));private final List<Map<String,Object>> projects=new CopyOnWriteArrayList<>();public SchoolController(){for(int i=1;i<=15;i++){projects.add(Map.of("id",i,"schoolName","????"+i,"projectName","???? 2026 ?????","deadline",LocalDate.now().plusDays(i*5).toString(),"requirements","??? 30%??? 500+?????????","materials","?????????????????????","matchScore",70+i));}}@GetMapping("/api/schools") public ApiResponse<?> schools(){return ApiResponse.success(schools);}@PostMapping("/api/schools") public ApiResponse<?> addSchool(@RequestBody Map<String,Object> s){s.put("id",IdGenerator.nextId());schools.add(s);return ApiResponse.success(s);}@GetMapping("/api/school-projects") public ApiResponse<?> projects(){return ApiResponse.success(projects);}@PostMapping("/api/school-projects") public ApiResponse<?> addProject(@RequestBody Map<String,Object> p){p.put("id",IdGenerator.nextId());projects.add(p);return ApiResponse.success(p);}@PostMapping("/api/schools/recommend") public ApiResponse<?> recommend(@RequestBody Map<String,Object> profile){return ApiResponse.success(projects.stream().limit(5).toList());}}
